// ---- Module state (not persisted; reset on entry) ----
var _mapSelected = null;
var _mapDistrict = null;
var _mapRegion = "All";

function mapResetState() {
    _mapSelected = null;
    _mapDistrict = null;
    _mapRegion = "All";
}

function getMillPin(key) {
    for (var i = 0; i < MILL_MAP_PINS.length; i++) {
        if (MILL_MAP_PINS[i].key === key) return MILL_MAP_PINS[i];
    }
    return null;
}

function getMillPinByName(name) {
    for (var i = 0; i < MILL_MAP_PINS.length; i++) {
        if (MILL_MAP_PINS[i].name === name) return MILL_MAP_PINS[i];
    }
    return null;
}

// ---- SVG builders ----

function mapCoastPath(poly) {
    var d = "";
    for (var i = 0; i < poly.length; i++) {
        var p = mapProject(poly[i][0], poly[i][1]);
        d += (i === 0 ? "M" : "L") + p.x.toFixed(1) + "," + p.y.toFixed(1);
    }
    return d + "Z";
}

// labelMode: "none" | "short" (always-on compact label). The full
// name still appears above the selected pin.
function mapPinMarkerSVG(pin, x, y, idx, labelMode) {
    var dim = _mapRegion !== "All" && pin.region !== _mapRegion;
    var cls = "map-pin" + (pin.type === "origin" ? " map-pin--origin" : "") +
        (_mapSelected === pin.key ? " sel" : "") + (dim ? " dim" : "");
    var mark;
    if (pin.type === "origin") {
        mark =
            '<circle class="map-pin-ring map-pin-ring--dash" cx="0" cy="0" r="8"/>' +
            '<rect class="map-pin-dot" x="-3" y="-3" width="6" height="6" transform="rotate(45)"/>';
    } else {
        mark =
            '<circle class="map-pin-ring" cx="0" cy="0" r="7"/>' +
            '<circle class="map-pin-dot" cx="0" cy="0" r="2.7"/>';
    }
    var label = "";
    if (_mapSelected === pin.key) {
        label = '<text class="map-pin-name" x="0" y="-14">' + pin.name + "</text>";
    } else if (labelMode === "short") {
        var tag = pin.short !== undefined ? pin.short : pin.name;
        if (tag) {
            label = '<text class="map-pin-tag" x="0" y="' + (pin.labelDy || 20) + '">' + tag + "</text>";
        }
    }
    return (
        '<g class="' + cls + '" style="animation-delay:' + (idx * 45) + 'ms" transform="translate(' + x.toFixed(1) + "," + y.toFixed(1) + ')" data-action="map-pin" data-key="' + pin.key +
        '" role="button" tabindex="0" aria-label="' + pin.name + ", " + pin.place + '">' +
        '<circle class="map-pin-hit" cx="0" cy="0" r="20"/>' +
        mark +
        label +
        "</g>"
    );
}

function getMillMapSVG() {
    var svg = '<svg class="map-chart" viewBox="0 0 ' + MAP_W + " " + MAP_H + '" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid meet">';

    // Graticule every 5 degrees
    var g, p1, p2;
    for (g = MAP_LON_MIN + 1 + ((4 - ((MAP_LON_MIN + 1) % 5)) % 5); g < MAP_LON_MAX; g += 5) {
        p1 = mapProject(g, MAP_LAT_MIN); p2 = mapProject(g, MAP_LAT_MAX);
        svg += '<line class="map-grid" x1="' + p1.x.toFixed(1) + '" y1="' + p1.y.toFixed(1) + '" x2="' + p2.x.toFixed(1) + '" y2="' + p2.y.toFixed(1) + '"/>';
    }
    for (g = 30; g <= 60; g += 5) {
        p1 = mapProject(MAP_LON_MIN, g); p2 = mapProject(MAP_LON_MAX, g);
        svg += '<line class="map-grid" x1="' + p1.x.toFixed(1) + '" y1="' + p1.y.toFixed(1) + '" x2="' + p2.x.toFixed(1) + '" y2="' + p2.y.toFixed(1) + '"/>';
    }

    // Land
    for (var c = 0; c < MAP_COASTS.length; c++) {
        svg += '<path class="map-land" d="' + mapCoastPath(MAP_COASTS[c]) + '"/>';
    }

    // Labels
    var i, p;
    for (i = 0; i < MAP_PLACE_LABELS.length; i++) {
        p = mapProject(MAP_PLACE_LABELS[i][1], MAP_PLACE_LABELS[i][2]);
        svg += '<text class="map-place-label" x="' + p.x.toFixed(1) + '" y="' + p.y.toFixed(1) + '">' + MAP_PLACE_LABELS[i][0] + "</text>";
    }
    for (i = 0; i < MAP_SEA_LABELS.length; i++) {
        p = mapProject(MAP_SEA_LABELS[i][1], MAP_SEA_LABELS[i][2]);
        svg += '<text class="map-sea-label" x="' + p.x.toFixed(1) + '" y="' + p.y.toFixed(1) + '">' + MAP_SEA_LABELS[i][0] + "</text>";
    }

    // District cluster markers
    var idx = 0;
    for (var dk in MAP_DISTRICTS) {
        var d = MAP_DISTRICTS[dk];
        var count = 0;
        for (i = 0; i < MILL_MAP_PINS.length; i++) {
            if (MILL_MAP_PINS[i].cluster === dk) count++;
        }
        var dp = mapProject(d.lon, d.lat);
        var dimD = _mapRegion !== "All" && ((dk === "yorkshire" && _mapRegion !== "Britain") || (dk === "n_italy" && _mapRegion !== "Italy"));
        svg +=
            '<g class="map-cluster' + (dimD ? " dim" : "") + '" style="animation-delay:' + (idx++ * 45) + 'ms" transform="translate(' + dp.x.toFixed(1) + "," + dp.y.toFixed(1) + ')" data-action="map-cluster" data-district="' + dk +
            '" role="button" tabindex="0" aria-label="' + d.name + ", " + count + ' houses — open district chart">' +
            '<circle class="map-pin-hit" cx="0" cy="0" r="26"/>' +
            '<circle class="map-cluster-disc" cx="0" cy="0" r="13"/>' +
            '<text class="map-cluster-count" x="0" y="4">' + count + "</text>" +
            '<text class="map-cluster-name" x="0" y="27">' + (d.mapLabel || d.name) + "</text>" +
            "</g>";
    }

    // Free-standing pins (not clustered, not the inset)
    for (i = 0; i < MILL_MAP_PINS.length; i++) {
        var pin = MILL_MAP_PINS[i];
        if (pin.cluster || pin.type === "inset") continue;
        p = mapProject(pin.lon, pin.lat);
        svg += mapPinMarkerSVG(pin, p.x, p.y, idx++, "short");
    }

    // Singapore inset, top right (empty Baltic corner): home is off
    // this chart's edge entirely.
    var ins = getMillPin("officine_paladino");
    var insDim = _mapRegion !== "All" && _mapRegion !== "Singapore";
    svg +=
        '<g class="map-inset' + (insDim ? " dim" : "") + '" transform="translate(' + (MAP_W - 96) + ',96)">' +
        '<circle class="map-inset-ring" cx="0" cy="0" r="62"/>' +
        '<text class="map-inset-eyebrow" x="0" y="-30">10,000 km east</text>' +
        '<g class="map-pin' + (_mapSelected === ins.key ? " sel" : "") + '" data-action="map-pin" data-key="officine_paladino"' +
        ' role="button" tabindex="0" aria-label="' + ins.name + ", " + ins.place + '">' +
        '<circle class="map-pin-hit" cx="0" cy="0" r="26"/>' +
        '<circle class="map-pin-ring" cx="0" cy="0" r="7"/>' +
        '<circle class="map-pin-dot" cx="0" cy="0" r="2.7"/>' +
        "</g>" +
        '<text class="map-inset-name" x="0" y="24">Singapore</text>' +
        '<text class="map-inset-sub" x="0" y="40">home</text>' +
        "</g>";

    svg += "</svg>";
    return svg;
}

// District chart: the cluster's pins spread across their own frame,
// projected from the district's own bounding box.
function getDistrictSVG(districtKey) {
    var d = MAP_DISTRICTS[districtKey];
    var pins = [];
    var i;
    for (i = 0; i < MILL_MAP_PINS.length; i++) {
        if (MILL_MAP_PINS[i].cluster === districtKey) pins.push(MILL_MAP_PINS[i]);
    }
    var minLon = Infinity, maxLon = -Infinity, minLat = Infinity, maxLat = -Infinity;
    function grow(lon, lat) {
        if (lon < minLon) minLon = lon; if (lon > maxLon) maxLon = lon;
        if (lat < minLat) minLat = lat; if (lat > maxLat) maxLat = lat;
    }
    for (i = 0; i < pins.length; i++) grow(pins[i].lon, pins[i].lat);
    for (i = 0; i < d.places.length; i++) grow(d.places[i][1], d.places[i][2]);

    var W = 730, H = 560, PAD = 76;
    var lonSpan = Math.max(maxLon - minLon, 0.001), latSpan = Math.max(maxLat - minLat, 0.001);
    function proj(lon, lat) {
        return {
            x: PAD + (lon - minLon) / lonSpan * (W - 2 * PAD),
            y: (H - PAD) - (lat - minLat) / latSpan * (H - 2 * PAD),
        };
    }

    var svg = '<svg class="map-chart map-chart--district" viewBox="0 0 ' + W + " " + H + '" xmlns="http://www.w3.org/2000/svg" preserveAspectRatio="xMidYMid meet">';
    for (var gx = 1; gx < 6; gx++) {
        svg += '<line class="map-grid" x1="' + (W / 6 * gx) + '" y1="0" x2="' + (W / 6 * gx) + '" y2="' + H + '"/>';
    }
    for (var gy = 1; gy < 4; gy++) {
        svg += '<line class="map-grid" x1="0" y1="' + (H / 4 * gy) + '" x2="' + W + '" y2="' + (H / 4 * gy) + '"/>';
    }
    var p;
    for (i = 0; i < d.places.length; i++) {
        p = proj(d.places[i][1], d.places[i][2]);
        svg += '<text class="map-place-label map-place-label--town" x="' + p.x.toFixed(1) + '" y="' + (p.y + 22).toFixed(1) + '">' + d.places[i][0] + "</text>";
        svg += '<line class="map-town-tick" x1="' + p.x.toFixed(1) + '" y1="' + (p.y + 6).toFixed(1) + '" x2="' + p.x.toFixed(1) + '" y2="' + (p.y + 12).toFixed(1) + '"/>';
    }
    // Real mill towns sit within a few km of each other (half of Biella
    // is inside one valley), so projected pins collide. Relax them
    // apart with a few rounds of pairwise repulsion — positions stay
    // near-true, labels stay readable. Towns keep their exact spots.
    var placed = [];
    for (i = 0; i < pins.length; i++) {
        p = proj(pins[i].lon, pins[i].lat);
        placed.push({ x: p.x, y: p.y });
    }
    var MIN_X = 92, MIN_Y = 34;
    for (var pass = 0; pass < 80; pass++) {
        var moved = false;
        for (i = 0; i < placed.length; i++) {
            for (var j = i + 1; j < placed.length; j++) {
                var dx = placed[j].x - placed[i].x;
                var dy = placed[j].y - placed[i].y;
                // Labels are wide and short: treat the exclusion zone as
                // an ellipse, and only push apart when both axes overlap.
                var ox = MIN_X - Math.abs(dx);
                var oy = MIN_Y - Math.abs(dy);
                if (ox <= 0 || oy <= 0) continue;
                moved = true;
                // Resolve along the cheaper axis.
                if (ox / MIN_X < oy / MIN_Y) {
                    var sx = (dx >= 0 ? 1 : -1) * ox / 2;
                    placed[i].x -= sx; placed[j].x += sx;
                } else {
                    var sy = (dy >= 0 ? 1 : -1) * oy / 2;
                    placed[i].y -= sy; placed[j].y += sy;
                }
            }
        }
        for (i = 0; i < placed.length; i++) {
            placed[i].x = Math.max(46, Math.min(W - 46, placed[i].x));
            placed[i].y = Math.max(34, Math.min(H - 30, placed[i].y));
        }
        if (!moved) break;
    }
    // Hairlines back to true position, so the relaxation stays honest
    for (i = 0; i < pins.length; i++) {
        p = proj(pins[i].lon, pins[i].lat);
        if (Math.abs(p.x - placed[i].x) + Math.abs(p.y - placed[i].y) > 6) {
            svg += '<line class="map-leader" x1="' + p.x.toFixed(1) + '" y1="' + p.y.toFixed(1) +
                '" x2="' + placed[i].x.toFixed(1) + '" y2="' + placed[i].y.toFixed(1) + '"/>';
        }
    }
    for (i = 0; i < pins.length; i++) {
        svg += mapPinMarkerSVG(pins[i], placed[i].x, placed[i].y, i, "short");
    }
    svg += "</svg>";
    return svg;
}

// ---- HTML builders ----

function getMapDetailHTML(pin) {
    if (!pin) {
        return (
            '<div class="map-detail-empty">Tap a marker to meet the house behind the cloth.</div>'
        );
    }
    var meta = pin.place + (pin.est ? " &middot; Est. " + pin.est : "");
    var links =
        '<button class="vis-guide-link" data-action="result-link" data-path=\'' +
        JSON.stringify(pin.guidePath) + "'>Read the guide &rarr;</button>";
    if (pin.fabricKey) {
        links +=
            '<button class="vis-guide-link" data-action="map-see-cloth" data-fabric="' + pin.fabricKey + '">See its cloth &rarr;</button>';
    }
    return (
        '<div class="map-detail-head">' +
        '<h2 class="map-detail-name">' + pin.name + "</h2>" +
        '<div class="map-detail-meta">' + meta + "</div>" +
        "</div>" +
        '<p class="map-detail-blurb">' + pin.blurb + "</p>" +
        '<div class="map-detail-links">' + links + "</div>"
    );
}

function getMapChipsHTML() {
    var regions = ["All", "Britain", "Ireland", "France", "Italy", "Switzerland", "Turkey", "Egypt", "Singapore"];
    var html = "";
    for (var i = 0; i < regions.length; i++) {
        html +=
            '<button class="map-chip' + (_mapRegion === regions[i] ? " sel" : "") + '" data-action="map-region" data-region="' + regions[i] + '">' + regions[i] + "</button>";
    }
    return html;
}

// ============================================
// THE PROVENANCE TAPE
//
// 29 of the houses carry a founding year, and they span 1663 to 2021 —
// Vitale Barberis Canonico was weaving 113 years before American
// independence, Officine Paladino opened in 2017. That range was
// sitting unused in the data.
//
// Drawn as a tape blade rather than a generic timeline, because the
// tape measure is already the app's signature: it runs through quiz
// progress, the loading interstitial and the welcome backdrop. Here it
// measures years instead of inches.
//
// Horizontal scroll is the right axis: a century reads as a distance,
// and swiping a long blade is a natural iPad gesture.
// ============================================

// 1.6 packed 29 houses into ~570px and the labels collided into
// unreadable slivers. At 8 the blade runs ~2900px, which is the point:
// three and a half centuries should feel like a distance you travel.
var TAPE_PX_PER_YEAR = 8;

function getProvenanceTapeHTML() {
    var dated = [];
    for (var i = 0; i < MILL_MAP_PINS.length; i++) {
        if (MILL_MAP_PINS[i].est) dated.push(MILL_MAP_PINS[i]);
    }
    if (dated.length < 2) return "";
    dated.sort(function (a, b) { return a.est - b.est; });

    var first = dated[0].est, last = dated[dated.length - 1].est;
    var startY = Math.floor(first / 50) * 50;
    var endY = Math.ceil(last / 50) * 50;
    var width = (endY - startY) * TAPE_PX_PER_YEAR;

    // Century and half-century ticks, like the graduations on a blade.
    var ticks = "";
    for (var y = startY; y <= endY; y += 10) {
        var major = y % 100 === 0;
        var half = y % 50 === 0;
        if (!half && !major) continue;
        var left = (y - startY) * TAPE_PX_PER_YEAR;
        ticks +=
            '<span class="ptape-tick' + (major ? " major" : "") + '" style="left:' + left + 'px"></span>' +
            (major ? '<span class="ptape-year" style="left:' + left + 'px">' + y + "</span>" : "");
    }

    // Labels are packed into lanes rather than simply alternated. The
    // 1860s-80s stretch has houses one and two years apart, so two rows
    // still collided into unreadable slivers. Each house takes the first
    // lane whose previous label has cleared it — the standard fix for
    // dense timeline labelling, and it means no label ever overlaps
    // another regardless of how tight the founding years get.
    var LANES = [-2, -1, 1, 2];          // two above the blade, two below
    var LANE_CLEAR = 104;                 // widest label plus breathing room
    var laneEnd = [-1e9, -1e9, -1e9, -1e9];

    var marks = "";
    for (var m = 0; m < dated.length; m++) {
        var h = dated[m];
        var x = (h.est - startY) * TAPE_PX_PER_YEAR;

        var lane = 0;
        for (var L = 0; L < LANES.length; L++) {
            if (x - laneEnd[L] >= LANE_CLEAR) { lane = L; break; }
            // If none is clear, fall back to the emptiest lane.
            if (L === LANES.length - 1) {
                lane = laneEnd.indexOf(Math.min.apply(null, laneEnd));
            }
        }
        laneEnd[lane] = x;

        var depth = LANES[lane];
        marks +=
            '<button class="ptape-house lane' + lane + (depth < 0 ? " up" : " down") + '"' +
            ' style="left:' + x + 'px"' +
            ' data-action="result-link" data-path=\'' + JSON.stringify(h.guidePath) + "'" +
            ' aria-label="' + h.name + ", founded " + h.est + '">' +
            '<span class="ptape-stem"></span>' +
            '<span class="ptape-label"><em>' + h.est + "</em>" + (h.short || h.name) + "</span>" +
            "</button>";
    }

    return (
        '<div class="ptape-block">' +
        '<div class="ptape-head">' +
        '<h2 class="ptape-title">' + (last - first) + " Years of Weaving</h2>" +
        '<p class="ptape-lead">The houses in this room were founded across three and a half centuries &mdash; ' +
        (dated[0].short || dated[0].name) + " in " + first + ", " +
        (dated[dated.length - 1].short || dated[dated.length - 1].name) + " in " + last +
        ". Drag the blade.</p>" +
        "</div>" +
        '<div class="ptape-scroll" id="ptape-scroll">' +
        '<div class="ptape-rail" style="width:' + (width + 120) + 'px">' +
        '<span class="ptape-blade"></span>' +
        ticks + marks +
        "</div>" +
        "</div>" +
        "</div>"
    );
}

function getMapIndexHTML() {
    var order = ["Britain", "Ireland", "France", "Italy", "Switzerland", "Turkey", "Egypt", "Singapore"];
    var html = "";
    for (var r = 0; r < order.length; r++) {
        var entries = "";
        for (var i = 0; i < MILL_MAP_PINS.length; i++) {
            var pin = MILL_MAP_PINS[i];
            if (pin.region !== order[r]) continue;
            entries +=
                '<button class="map-index-entry' + (_mapSelected === pin.key ? " sel" : "") + '" data-action="map-pin" data-key="' + pin.key + '">' +
                '<span class="map-index-name">' + pin.name + "</span>" +
                '<span class="map-index-place">' + pin.place + "</span>" +
                "</button>";
        }
        html +=
            '<div class="map-index-group">' +
            '<div class="map-index-region">' + order[r] + "</div>" +
            entries +
            "</div>";
    }
    return html;
}

function getMapStageHTML() {
    if (_mapDistrict) {
        var d = MAP_DISTRICTS[_mapDistrict];
        return (
            '<div class="map-district-bar">' +
            '<button class="map-zoom-out" data-action="map-zoom-out">&larr; The full chart</button>' +
            '<div class="map-district-title">' + d.name + '<span class="map-district-sub">' + d.sub + "</span></div>" +
            "</div>" +
            getDistrictSVG(_mapDistrict)
        );
    }
    return getMillMapSVG();
}

// ============================================
// THE GLOBE
//
// COBE (vendored, MIT, 12.9KB, no network) renders a dotted world with
// markers placed by real lat/long — which every pin in MILL_MAP_PINS
// already carries, so no new data was needed.
//
// It OPENS Cloth Origins rather than replacing the chart below it. A
// globe cannot show the district detail: at world scale the 18 houses
// around Biella collapse into a single dot, and de-overlapping those is
// most of what the flat chart exists to do. So the globe answers "where
// in the world does BBS cloth come from" and the chart answers "which
// houses, and exactly where".
//
// Styling is house tokens, not COBE's defaults: ink land on a cream
// sphere with bronze markers and no glow, so it reads as an engraved
// terrestrial globe rather than a WebGL object dropped into an
// editorial app.
// ============================================

var _globeHandle = null;
var _globeRAF = null;

// Measured, not fitted. tmp/probe.js renders an isolated globe carrying
// a SINGLE marker at a known lat/lon and reads back where COBE actually
// draws it — two known points pin the mapping down exactly.
//
// At phi 0, longitude -90 lands dead centre, so the offset is +90.
//
// The second constant is the one that matters and is easy to miss: the
// sphere fills only ~0.848 of the canvas half-width, because COBE
// leaves margin around it for the glow. An earlier attempt fitted the
// offset against the real overlapping markers WITHOUT this term and
// produced a confident, plausible, wrong answer (51 degrees).
//
// Re-run tmp/probe.js if the COBE version changes.
var GLOBE_PHI_OFFSET = Math.PI / 2;
var GLOBE_RADIUS_SCALE = 0.848;

// Clickable groups, sized to what a globe can actually resolve.
//
// One pin per country was the obvious first move and it was wrong:
// Britain, Ireland, France, Italy and Switzerland fall within about
// 40px of each other on a 419px globe, so five 44px touch targets ended
// up stacked on top of one another and a tap on Italy landed on a
// neighbour. It is the same limit that stops the globe resolving the 21
// houses around Biella — at world scale, Europe is one place.
//
// So the globe carries four well-separated groups. Fine filtering by
// country stays where it works: the chips and the chart below.
// Turkey and Egypt land 23px apart — still overlapping 44px targets, so
// the same problem one level down. They merge into "Cotton", which is
// not a fudge: Soktas weaves cotton shirtings and the Nile Delta is a
// cotton origin, so at globe scale they are one place AND one story,
// against the wool houses of Europe.
var GLOBE_GROUPS = [
    { key: "Europe", label: "Europe", regions: ["Britain", "Ireland", "France", "Italy", "Switzerland"] },
    { key: "Cotton", label: "Cotton", regions: ["Turkey", "Egypt"] },
    { key: "Singapore", label: "Singapore", regions: ["Singapore"] }
];

function getMillGlobeRegions() {
    var out = [];
    for (var g = 0; g < GLOBE_GROUPS.length; g++) {
        var grp = GLOBE_GROUPS[g];
        var lat = 0, lon = 0, n = 0;
        for (var i = 0; i < MILL_MAP_PINS.length; i++) {
            var p = MILL_MAP_PINS[i];
            if (typeof p.lat !== "number" || typeof p.lon !== "number") continue;
            if (grp.regions.indexOf(p.region) === -1) continue;
            lat += p.lat; lon += p.lon; n++;
        }
        if (!n) continue;
        out.push({
            region: grp.regions.length === 1 ? grp.regions[0] : "All",
            label: grp.label,
            lat: lat / n,
            lon: lon / n,
            count: n
        });
    }
    return out;
}

function getMillGlobeHTML() {
    var regions = getMillGlobeRegions();
    var pins = "";
    for (var i = 0; i < regions.length; i++) {
        var r = regions[i];
        pins +=
            '<button class="map-globe-pin" data-action="map-globe-region" data-region="' + r.region + '"' +
            ' data-lat="' + r.lat + '" data-lon="' + r.lon + '"' +
            ' aria-label="' + r.label + ", " + r.count + (r.count === 1 ? " house" : " houses") + '">' +
            '<span class="map-globe-pin-dot"></span>' +
            '<span class="map-globe-pin-label">' + r.label + '<em>' + r.count + "</em></span>" +
            "</button>";
    }
    return (
        '<div class="map-globe-block">' +
        '<div class="map-globe-stage" id="map-globe-stage">' +
        '<canvas class="map-globe" id="map-globe" aria-hidden="true"></canvas>' +
        '<div class="map-globe-pins" id="map-globe-pins">' + pins + "</div>" +
        "</div>" +
        '<p class="map-globe-note">Drag to turn the globe &middot; tap a region to filter the chart</p>' +
        "</div>"
    );
}

function startMillGlobe() {
    if (_globeRAF) { cancelAnimationFrame(_globeRAF); _globeRAF = null; }
    if (_globeHandle && _globeHandle.destroy) { _globeHandle.destroy(); _globeHandle = null; }

    var cv = document.getElementById("map-globe");
    // No WebGL, no COBE, or a browser that cannot run it: the chart
    // below is the real feature, so the globe simply does not appear.
    if (!cv || typeof window.createGlobe !== "function") {
        var block = cv && cv.closest(".map-globe-block");
        if (block) block.style.display = "none";
        return;
    }

    var markers = [];
    for (var i = 0; i < MILL_MAP_PINS.length; i++) {
        var p = MILL_MAP_PINS[i];
        if (typeof p.lat !== "number" || typeof p.lon !== "number") continue;
        markers.push({ location: [p.lat, p.lon], size: p.type === "origin" ? 0.045 : 0.06 });
    }

    var rect = cv.getBoundingClientRect();
    var side = Math.max(280, Math.min(rect.width, 560));
    var dark = document.documentElement.getAttribute("data-theme") === "dark";

    // Opens on Europe, where 38 of the 40 houses are. Derived from the
    // calibrated offset rather than guessed: centring longitude L needs
    // lon + phi + offset = 0, so phi = -L - offset. L is ~3.6 degrees,
    // the mean of the British and Italian clusters.
    var phi = -(3.6 * Math.PI / 180) - GLOBE_PHI_OFFSET;
    var theta = 0.28;
    var dragging = false;
    var lastX = 0;
    // Reduced motion stops the idle spin but keeps drag working — the
    // globe stays fully usable, it just does not move on its own.
    var reduced = window.matchMedia && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    var spin = reduced ? 0 : 0.0022;

    // COBE 2.x has NO `onRender` callback — that is the 0.x API. Here
    // the caller owns the loop and pushes new state in with update().
    var dpr = Math.min(window.devicePixelRatio || 1, 2);

    try {
        _globeHandle = window.createGlobe(cv, {
            devicePixelRatio: dpr,
            width: side * dpr,
            height: side * dpr,
            phi: phi,
            theta: theta,
            dark: dark ? 1 : 0,
            diffuse: 1.15,
            mapSamples: 15000,
            mapBrightness: dark ? 5.2 : 2.9,
            baseColor: dark ? [0.16, 0.16, 0.15] : [0.937, 0.925, 0.902],
            markerColor: [0.541, 0.427, 0.263],
            glowColor: dark ? [0.18, 0.18, 0.17] : [0.965, 0.957, 0.941],
            markers: markers,
            // Keeps the drawn frame readable after compositing, which
            // is what makes the globe screenshot-able at all — WebGL
            // canvases otherwise return a blank buffer to any capture.
            context: { preserveDrawingBuffer: true }
        });
    } catch (err) {
        var b2 = cv.closest(".map-globe-block");
        if (b2) b2.style.display = "none";
        return;
    }

    // Region buttons are positioned by projecting their centroid onto
    // the sphere each frame. COBE does emit per-marker CSS variables,
    // but their shape is undocumented and version-dependent; projecting
    // here is deterministic, testable, and lets the pins be real focusable
    // buttons with real touch targets rather than decorated divs.
    var pinEls = [];
    var pinWrap = document.getElementById("map-globe-pins");
    if (pinWrap) {
        var nodes = pinWrap.querySelectorAll(".map-globe-pin");
        for (var q = 0; q < nodes.length; q++) {
            pinEls.push({
                el: nodes[q],
                lat: parseFloat(nodes[q].getAttribute("data-lat")) * Math.PI / 180,
                lon: parseFloat(nodes[q].getAttribute("data-lon")) * Math.PI / 180
            });
        }
    }

    // The drawn sphere is smaller than the canvas, so pins project
    // against the sphere radius rather than the half-canvas.
    var RAD = side / 2;
    var SPHERE = RAD * GLOBE_RADIUS_SCALE;

    function placePins() {
        for (var i = 0; i < pinEls.length; i++) {
            var m = pinEls[i];
            // Orthographic projection. PHI_OFFSET aligns our longitudes
            // with COBE's texture rotation; verified by checking a pin
            // lands on its own bronze marker.
            var lam = m.lon + phi + GLOBE_PHI_OFFSET;
            var x = Math.cos(m.lat) * Math.sin(lam);
            var y = Math.cos(theta) * Math.sin(m.lat) - Math.sin(theta) * Math.cos(m.lat) * Math.cos(lam);
            var z = Math.sin(theta) * Math.sin(m.lat) + Math.cos(theta) * Math.cos(m.lat) * Math.cos(lam);

            if (z <= 0.04) {
                // On the far side of the globe — not merely faded, but
                // removed from the tab order and from hit-testing.
                m.el.style.opacity = "0";
                m.el.style.pointerEvents = "none";
                m.el.setAttribute("tabindex", "-1");
                m.el.setAttribute("aria-hidden", "true");
                continue;
            }
            m.el.style.opacity = String(Math.min(1, (z - 0.04) * 4));
            m.el.style.pointerEvents = "auto";
            m.el.removeAttribute("tabindex");
            m.el.removeAttribute("aria-hidden");
            // The button is a zero-size anchor: its dot is centred on
            // this point and the label hangs off to the right. Centring
            // the whole button instead (translate -50%,-50%) put the dot
            // well left of the real position, because the label is part
            // of the box being centred.
            m.el.style.transform =
                "translate(" + (RAD + x * SPHERE) + "px," + (RAD - y * SPHERE) + "px)";
        }
    }

    function tick() {
        if (!cv.isConnected || !_globeHandle) { _globeRAF = null; return; }
        if (!dragging) phi += spin;
        _globeHandle.update({ phi: phi, theta: theta });
        placePins();
        _globeRAF = requestAnimationFrame(tick);
    }
    tick();

    cv.style.width = side + "px";
    cv.style.height = side + "px";

    // Drag to turn. pointer events cover touch and mouse alike; the
    // delegated click handler is untouched.
    // The idle spin is an invitation, not a feature. Once someone
    // touches the globe it stops for good: a pin that drifts a couple
    // of centimetres a second is genuinely hard to hit on a touchscreen,
    // and the whole point of the pins is that they are tappable.
    var stage = document.getElementById("map-globe-stage");
    if (stage) {
        stage.addEventListener("pointerdown", function () { spin = 0; }, { passive: true });

        // Taps are resolved by explicit hit-testing against the pin
        // positions this loop already computes, rather than by relying
        // on the browser to hit-test a moving, opacity-animated element
        // sitting inside a pointer-events:none wrapper. That layering
        // proved genuinely unreliable — a tap could land on the wrapper
        // and do nothing — and it would be no more reliable under a
        // finger than under a test. The DOM buttons remain for
        // visibility and keyboard access; this makes touch dependable.
        var downX = 0, downY = 0, downT = 0;
        stage.addEventListener("pointerdown", function (e) {
            downX = e.clientX; downY = e.clientY; downT = Date.now();
        }, { passive: true });

        stage.addEventListener("pointerup", function (e) {
            // A drag turns the globe; only a tap selects.
            if (Math.abs(e.clientX - downX) > 10 || Math.abs(e.clientY - downY) > 10) return;
            if (Date.now() - downT > 700) return;

            var stageRect = stage.getBoundingClientRect();
            var px = e.clientX - stageRect.left;
            var py = e.clientY - stageRect.top;

            var best = null, bestD = 34; // within a finger's width of the dot
            for (var i = 0; i < pinEls.length; i++) {
                var el = pinEls[i].el;
                if (el.getAttribute("aria-hidden") === "true") continue;
                var r = el.getBoundingClientRect();
                var cx = r.left + r.width / 2 - stageRect.left;
                var cy = r.top + r.height / 2 - stageRect.top;
                var d = Math.sqrt((px - cx) * (px - cx) + (py - cy) * (py - cy));
                if (d < bestD) { bestD = d; best = el; }
            }
            if (best) best.click();
        }, { passive: true });
    }

    cv.addEventListener("pointerdown", function (e) {
        dragging = true;
        lastX = e.clientX;
        cv.setPointerCapture && cv.setPointerCapture(e.pointerId);
    });
    cv.addEventListener("pointermove", function (e) {
        if (!dragging) return;
        phi += (e.clientX - lastX) * 0.006;
        lastX = e.clientX;
    });
    ["pointerup", "pointercancel", "pointerleave"].forEach(function (evt) {
        cv.addEventListener(evt, function () { dragging = false; });
    });
}

function stopMillGlobe() {
    if (_globeRAF) { cancelAnimationFrame(_globeRAF); _globeRAF = null; }
    if (_globeHandle && _globeHandle.destroy) _globeHandle.destroy();
    _globeHandle = null;
}

function renderMillMap() {
    var houses = 0, origins = 0;
    for (var i = 0; i < MILL_MAP_PINS.length; i++) {
        if (MILL_MAP_PINS[i].type === "origin") origins++;
        else houses++;
    }
    return (
        '<div class="vis-shell map-shell">' +
        '<div class="vis-eyebrow">The Provenance Chart</div>' +
        "<h1 class=\"vis-title\">Where the Cloth Comes From</h1>" +
        '<p class="vis-lead">' + houses + " houses and " + (origins === 1 ? "one cotton origin" : origins + " cotton origins") + ", charted. Tap a marker to meet the house behind the cloth &mdash; the numbered discs open the two great mill districts.</p>" +
        getMillGlobeHTML() +
        '<div class="map-chips">' + getMapChipsHTML() + "</div>" +
        '<div class="map-stage" id="map-stage">' + getMapStageHTML() + "</div>" +
        '<div class="vis-info map-detail" id="map-detail">' + getMapDetailHTML(getMillPin(_mapSelected)) + "</div>" +
        getProvenanceTapeHTML() +
        '<div class="map-index">' + getMapIndexHTML() + "</div>" +
        '<div class="vis-footnote">A stylised merchant’s chart &mdash; drawn for the story, not for navigation.</div>' +
        '<div class="nav-buttons"><button data-action="back">Back</button><button data-action="home">Home</button></div>' +
        "</div>"
    );
}

// ---- Partial updates ----

function mapRefreshStage() {
    var stage = document.getElementById("map-stage");
    if (stage) stage.innerHTML = getMapStageHTML();
}

function mapRefreshDetail() {
    var detail = document.getElementById("map-detail");
    if (detail) detail.innerHTML = getMapDetailHTML(getMillPin(_mapSelected));
}

function mapRefreshIndex() {
    var entries = document.querySelectorAll(".map-index-entry");
    for (var i = 0; i < entries.length; i++) {
        var isSel = entries[i].getAttribute("data-key") === _mapSelected;
        entries[i].className = "map-index-entry" + (isSel ? " sel" : "");
    }
}

function mapSelectPin(key) {
    var pin = getMillPin(key);
    if (!pin) return;
    _mapSelected = key;
    // A clustered pin picked from the index opens its district first.
    if (pin.cluster && _mapDistrict !== pin.cluster) _mapDistrict = pin.cluster;
    else if (!pin.cluster && _mapDistrict) _mapDistrict = null;
    mapRefreshStage();
    mapRefreshDetail();
    mapRefreshIndex();
}

function mapOpenDistrict(key) {
    if (!MAP_DISTRICTS[key]) return;
    _mapDistrict = key;
    mapRefreshStage();
}

function mapCloseDistrict() {
    _mapDistrict = null;
    mapRefreshStage();
}

function mapSetRegion(region) {
    _mapRegion = region;
    var chips = document.querySelectorAll(".map-chip");
    for (var i = 0; i < chips.length; i++) {
        var isSel = chips[i].getAttribute("data-region") === region;
        chips[i].className = "map-chip" + (isSel ? " sel" : "");
    }
    mapRefreshStage();
}

window.renderMillMap = renderMillMap;
